final class ModelPropertyExtension implements PropertiesClassReflectionExtension
{
    public function __construct(
        private ModelPropertyHelper $modelPropertyHelper,
    ) {
    }

    public function hasProperty(ClassReflection $classReflection, string $propertyName): bool
    {
        if ($this->modelPropertyHelper->hasAccessor($classReflection, $propertyName, strictGenerics: false)) {
            return false;
        }

        return $this->modelPropertyHelper->hasDatabaseProperty($classReflection, $propertyName);
    }

    public function getProperty(ClassReflection $classReflection, string $propertyName): PropertyReflection
    {
        return $this->modelPropertyHelper->getDatabaseProperty($classReflection, $propertyName);
    }
}

protected function addLookups($route)
    {
        // If the route has a name, we will add it to the name look-up table, so that we
        // will quickly be able to find the route associated with a name and not have
        // to iterate through every route every time we need to find a named route.
        if (($name = $route->getName()) && ! $this->inNameLookup($name)) {
            $this->nameList[$name] = $route;
        }

        // When the route is routing to a controller we will also store the action that
        // is used by the route. This will let us reverse route to controllers while
        // processing a request and easily generate URLs to the given controllers.
        $action = $route->getAction();

        if (($controller = $action['controller'] ?? null) && ! $this->inActionLookup($controller)) {
            $this->addToActionList($action, $route);
        }
    }

foreach (Arr::wrap($scopes) as $scope => $parameters) {
    // If the scope key is an integer, then the scope was passed as the value and
    // the parameter list is empty, so we will format the scope name and these
    // parameters here. Then, we'll be ready to call the scope on the model.
    if (is_int($scope)) {
        [$scope, $parameters] = [$parameters, []];
    }

    // Next we'll pass the scope callback to the callScope method which will take
    // care of grouping the "wheres" properly so the logical order doesn't get
    // messed up when adding scopes. Then we'll return back out the builder.
    $builder = $builder->callNamedScope(
        $scope, Arr::wrap($parameters)
    );
}

foreach ($this->scopes as $identifier => $scope) {
    if (! isset($builder->scopes[$identifier])) {
        continue;
    }

    $builder->callScope(function (self $builder) use ($scope) {
        // If the scope is a Closure we will just go ahead and call the scope with the
        // builder instance. The "callScope" method will properly group the clauses
        // that are added to this query so "where" clauses maintain proper logic.
        if ($scope instanceof Closure) {
            $scope($builder);
        }

        // If the scope is a scope object, we will call the apply method on this scope
        // passing in the builder and the model instance. After we run all of these
        // scopes we will return back the builder instance to the outside caller.
        if ($scope instanceof Scope) {
            $scope->apply($builder, $this->getModel());
        }
    });
}

foreach ($this->getListeners($event) as $listener) {
    $response = $listener($event, $payload);

    // If a response is returned from the listener and event halting is enabled
    // we will just return this response, and not call the rest of the event
    // listeners. Otherwise we will add the response on the response list.
    if ($halt && ! is_null($response)) {
        return $response;
    }

    // If a boolean false is returned from a listener, we will stop propagating
    // the event to any further listeners down in the chain, else we keep on
    // looping through the listeners and firing every one in our sequence.
    if ($response === false) {
        break;
    }

    $responses[] = $response;
}

class CorruptComponentPayloadException extends \Exception
{
    use BypassViewHandler;

    public function __construct()
    {
        parent::__construct(
            "Livewire encountered corrupt data when trying to hydrate a component. \n".
            "Ensure that the [name, id, data] of the Livewire component wasn't tampered with between requests."
        );
    }

    public function report(): bool
    {
        return ! config('app.debug');
    }

    // In debug mode, let Laravel render the full error page.
    // In production, return a generic 419 to avoid leaking details.
    public function render($request)
    {
        if (config('app.debug')) return false;

        return response('', 419);
    }
}

foreach ($expectedAttributes as $name) {
    // The developer may dynamically specify the array of custom attributes on this
    // validator instance. If the attribute exists in this array it is used over
    // the other ways of pulling the attribute name for this given attributes.
    if ($inlineAttribute = $this->getAttributeFromLocalArray($name)) {
        return $inlineAttribute;
    }

    // We allow for a developer to specify language lines for any attribute in this
    // application, which allows flexibility for displaying a unique displayable
    // version of the attribute name instead of the name used in an HTTP POST.
    if ($translatedAttribute = $this->getAttributeFromTranslations($name)) {
        return $translatedAttribute;
    }
}
